Use `cc.sys.isNative` to distinguish between JSB (native) and HTML5:

```typescript
if (cc.sys.isNative) {
    // Running on iOS, Android, or Windows via JSB
    cc.log('Native platform');
    const fileUtils = jsb.fileUtils;
} else {
    // Running in a web browser
    cc.log('Browser platform');
}
```

`cc.sys.isNative` is `true` when running through Cocos2d-x JSB bindings (iOS, Android, Windows native), and `false` when running in a browser (HTML5).

Use `cc.sys.isMobile`:

```typescript
if (cc.sys.isMobile) {
    cc.log('Running on mobile device');
    // Show touch controls
    this.showVirtualJoystick();
} else {
    cc.log('Running on desktop');
    // Show keyboard hints
    this.showKeyboardHints();
}
```

`cc.sys.isMobile` returns `true` on mobile platforms (iOS, Android, mobile browsers) and `false` on desktop platforms. For more specific detection, use `cc.sys.platform` with constants like `cc.sys.ANDROID` (3), `cc.sys.IPHONE` (4), `cc.sys.IPAD` (5), or `cc.sys.MOBILE_BROWSER` (100).

Use `cc.sys.platform` with platform constants:

```typescript
switch (cc.sys.platform) {
    case cc.sys.ANDROID:         // 3
        cc.log('Running on Android');
        break;
    case cc.sys.IPHONE:          // 4
        cc.log('Running on iPhone');
        break;
    case cc.sys.IPAD:            // 5
        cc.log('Running on iPad');
        break;
    case cc.sys.WIN32:           // 0
        cc.log('Running on Windows native');
        break;
    case cc.sys.MACOS:           // 2
        cc.log('Running on macOS native');
        break;
    case cc.sys.LINUX:           // 1
        cc.log('Running on Linux native');
        break;
    case cc.sys.MOBILE_BROWSER:  // 100
        cc.log('Running in mobile browser');
        break;
    case cc.sys.DESKTOP_BROWSER: // 101
        cc.log('Running in desktop browser');
        break;
}
```

Use `cc.sys.localStorage` for persistent key-value storage:

```typescript
// Save a string value
cc.sys.localStorage.setItem('playerName', 'Alice');

// Save a number (automatically converted to string)
cc.sys.localStorage.setItem('highscore', '5000');

// Load a value
const name = cc.sys.localStorage.getItem('playerName');
const scoreStr = cc.sys.localStorage.getItem('highscore');
const highscore = scoreStr ? parseInt(scoreStr) : 0;

// Save complex data as JSON
const playerData = { name: 'Alice', level: 5, coins: 120 };
cc.sys.localStorage.setItem('playerData', JSON.stringify(playerData));

// Load JSON data
const raw = cc.sys.localStorage.getItem('playerData');
const loaded = raw ? JSON.parse(raw) : { name: '', level: 1, coins: 0 };

// Remove a specific key
cc.sys.localStorage.removeItem('playerName');

// Clear ALL stored data
cc.sys.localStorage.clear();
```

`getItem` returns `string | null | undefined`, so always check for null/undefined before using the value.

Use `cc.sys.language` to get the system language code:

```typescript
function loadLocalization(): void {
    switch (cc.sys.language) {
        case cc.sys.LANGUAGE_ENGLISH:     // 'en'
            loadStrings('en');
            break;
        case cc.sys.LANGUAGE_CHINESE:     // 'zh'
            loadStrings('zh');
            break;
        case cc.sys.LANGUAGE_JAPANESE:    // 'ja'
            loadStrings('ja');
            break;
        case cc.sys.LANGUAGE_KOREAN:      // 'ko'
            loadStrings('ko');
            break;
        case cc.sys.LANGUAGE_FRENCH:      // 'fr'
            loadStrings('fr');
            break;
        case cc.sys.LANGUAGE_GERMAN:      // 'de'
            loadStrings('de');
            break;
        case cc.sys.LANGUAGE_SPANISH:     // 'es'
            loadStrings('es');
            break;
        default:
            loadStrings('en'); // fallback to English
            break;
