```typescript
// Join multiple path segments
const spritePath = cc.path.join('res', 'hero', 'hero.png');
// Result: 'res/hero/hero.png'

const levelPath = cc.path.join('res', 'levels', 'level1.json');
// Result: 'res/levels/level1.json'

