Complete the following code to build a platform-adaptive settings manager:

```typescript
class SettingsManager {
    // TODO: detect platform and set appropriate defaults
    // - Mobile: lower quality, touch controls
    // - Desktop: higher quality, keyboard/mouse controls
    // - Save/load settings via localStorage
}
```

output:
```typescript
interface GameSettings {
    graphicsQuality: 'low' | 'medium' | 'high';
    inputMode: 'touch' | 'keyboard' | 'gamepad';
    musicVolume: number;
    sfxVolume: number;
    showFps: boolean;
}

class SettingsManager {
    private static readonly STORAGE_KEY = 'game_settings';
    private _settings: GameSettings;

    constructor() {
        this._settings = this.loadOrCreateDefaults();
    }

    private createPlatformDefaults(): GameSettings {
        const isMobile = cc.sys.isMobile;
        const isNative = cc.sys.isNative;
        return {
            graphicsQuality: isMobile ? 'low' : 'high',
            inputMode: isMobile ? 'touch' : 'keyboard',
            musicVolume: 0.7,
            sfxVolume: 1.0,
            showFps: !isNative
        };
    }

    private loadOrCreateDefaults(): GameSettings {
        const raw = cc.sys.localStorage.getItem(SettingsManager.STORAGE_KEY);
        if (raw) {
            try {
                const loaded = JSON.parse(raw) as Partial<GameSettings>;
                const defaults = this.createPlatformDefaults();
                return { ...defaults, ...loaded };
            } catch (e) {
                cc.warn('Corrupt settings, using defaults');
            }
        }
        return this.createPlatformDefaults();
    }

    save(): void {
        cc.sys.localStorage.setItem(
            SettingsManager.STORAGE_KEY,
            JSON.stringify(this._settings)
        );
    }

    get settings(): Readonly<GameSettings> {
        return this._settings;
    }

    updateSetting<K extends keyof GameSettings>(key: K, value: GameSettings[K]): void {
        this._settings[key] = value;
        this.save();
    }
}
```

The manager detects the platform on first run, creates appropriate defaults, and merges with any previously saved settings.

instruction:
Find and fix the bug in this local storage code:

```typescript
class ScoreManager {
    saveHighScore(score: number): void {
        const current = cc.sys.localStorage.getItem('highscore');
        if (score > current) {
            cc.sys.localStorage.setItem('highscore', score);
        }
    }
}
```

output:
Two bugs:

**Bug 1: String comparison instead of number comparison.** `getItem` returns a `string | null | undefined`. Comparing a `number` with a `string` using `>` gives unreliable results (e.g., `"9" > 100` is `false` but `"9" > "100"` would depend on string ordering).

**Bug 2: No null check.** If no highscore exists yet, `current` is `null`, and `score > null` coerces `null` to `0` which works accidentally, but is fragile.

Fixed code:
```typescript
class ScoreManager {
    saveHighScore(score: number): void {
        const raw = cc.sys.localStorage.getItem('highscore');
        const current: number = raw ? parseInt(raw, 10) : 0;
        if (score > current) {
            cc.sys.localStorage.setItem('highscore', score.toString());
            cc.log('New high score:', score);
        }
    }

    getHighScore(): number {
        const raw = cc.sys.localStorage.getItem('highscore');
        return raw ? parseInt(raw, 10) : 0;
    }
}
```

Always parse `getItem` results to the correct type before comparison, and always convert values to strings before calling `setItem`.

instruction:
Review this code for issues:

```typescript
function initPlatformSpecific(): void {
    if (cc.sys.platform === 'android') {
        setupAndroidNotifications();
    }
    if (cc.sys.os === cc.sys.ANDROID) {
        setupAndroidUI();
    }
    if (cc.sys.language === 'chinese') {
        loadChineseFont();
    }
}
```

output:
Three issues:

**Issue 1:** `cc.sys.platform` is a **number**, not a string. Comparing with `'android'` always fails. Use `cc.sys.ANDROID` (which is `3`).

**Issue 2:** `cc.sys.os` is a **string** (e.g., `'Android'`), but `cc.sys.ANDROID` is a **number** (3, a platform constant). Should use `cc.sys.OS_ANDROID` (which is `'Android'`).

**Issue 3:** `cc.sys.language` uses language code constants, not the word `'chinese'`. Use `cc.sys.LANGUAGE_CHINESE` (which is `'zh'`).

Fixed code:
```typescript
function initPlatformSpecific(): void {
    if (cc.sys.platform === cc.sys.ANDROID) {
        // platform is number, ANDROID is 3
        setupAndroidNotifications();
    }
    if (cc.sys.os === cc.sys.OS_ANDROID) {
        // os is string, OS_ANDROID is 'Android'
        setupAndroidUI();
    }
    if (cc.sys.language === cc.sys.LANGUAGE_CHINESE) {
        // language uses code constants, LANGUAGE_CHINESE is 'zh'
        loadChineseFont();
    }
}
```

Key: `platform` → number constants (`ANDROID`, `IPHONE`, etc.), `os` → string constants (`OS_ANDROID`, `OS_IOS`, etc.), `language` → string codes (`LANGUAGE_CHINESE`, `LANGUAGE_ENGLISH`, etc.).

```typescript
// Get file extension
cc.path.extname('sprite.png')           // '.png'
cc.path.extname('res/audio/bgm.mp3')   // '.mp3'
cc.path.extname('data.level.json')      // '.json'
cc.path.extname('noextension')          // ''

// Get filename without extension
cc.path.basename('res/hero.png', '.png')   // 'hero'
cc.path.basename('audio/bgm.mp3', '.mp3')  // 'bgm'

// Get directory
cc.path.dirname('res/ui/button.png')       // 'res/ui'
cc.path.dirname('file.txt')                // ''

// Practical example: asset loader helper
function getAssetInfo(path: string): { dir: string; name: string; ext: string } {
    const ext = cc.path.extname(path);
    return {
        dir: cc.path.dirname(path),
        name: cc.path.basename(path, ext),
        ext: ext
    };
}

const info = getAssetInfo('res/sprites/hero.png');
// { dir: 'res/sprites', name: 'hero', ext: '.png' }
```

```typescript
cc.sys.isObjectValid(obj: object): boolean
```

This checks whether a Cocos2d-x native object has been destroyed or is still valid:

```typescript
const sprite = new cc.Sprite('res/hero.png');
parentNode.addChild(sprite);

// Later, after potential removal:
if (cc.sys.isObjectValid(sprite)) {
    sprite.setPosition(100, 200);
} else {
    cc.warn('Sprite has been destroyed');
}

// Common use case: deferred callbacks
function delayedAction(node: cc.Node): void {
    setTimeout(() => {
        if (!cc.sys.isObjectValid(node)) {
            cc.warn('Node was destroyed before callback executed');
            return;
        }
        node.setVisible(true);
    }, 2000);
}

// Useful in async operations:
cc.loader.loadJson('res/data.json', (err, data) => {
    if (!cc.sys.isObjectValid(this)) {
        return; // layer was destroyed during loading
    }
    this.processData(data);
});
```

This is especially important in JSB (native) where C++ objects can be garbage collected while JS references still exist.

Use `cc.sys.browserType` and `cc.sys.browserVersion` (available only on H5):

```typescript
if (!cc.sys.isNative) {
    cc.log('Browser:', cc.sys.browserType);    // 'chrome', 'safari', 'firefox', etc.
    cc.log('Version:', cc.sys.browserVersion);  // e.g., '91.0.4472'

    // Adapt behavior for specific browsers
    switch (cc.sys.browserType) {
        case 'chrome':
            cc.log('Running in Chrome');
            break;
        case 'safari':
            cc.log('Running in Safari');
            // Safari may need WebAudio workarounds
            break;
        case 'firefox':
            cc.log('Running in Firefox');
            break;
        default:
            cc.log('Unknown browser:', cc.sys.browserType);
            break;
    }

    // Get window resolution
