```

`browserType` and `browserVersion` are `string | null` — they're `null` on native platforms.

Use `gl` texture constants to control how textures are sampled:

```typescript
// Get a texture
const texture = cc.textureCache.addImage('res/sprite.png');

// Pixelated look (no interpolation) — great for pixel art
texture.setTexParameters(gl.NEAREST, gl.NEAREST, gl.CLAMP_TO_EDGE, gl.CLAMP_TO_EDGE);

// Smooth look (bilinear filtering) — great for HD art
texture.setTexParameters(gl.LINEAR, gl.LINEAR, gl.CLAMP_TO_EDGE, gl.CLAMP_TO_EDGE);

// Tiled/repeating texture
texture.setTexParameters(gl.LINEAR, gl.LINEAR, gl.REPEAT, gl.REPEAT);

// Mirrored repeating
texture.setTexParameters(gl.LINEAR, gl.LINEAR, gl.MIRRORED_REPEAT, gl.MIRRORED_REPEAT);
```

Filter constants:
```typescript
gl.NEAREST                  // pixelated
gl.LINEAR                   // smooth
gl.NEAREST_MIPMAP_NEAREST   // pixelated with mipmaps
gl.LINEAR_MIPMAP_LINEAR     // trilinear (smoothest)
```

Wrap constants:
```typescript
gl.CLAMP_TO_EDGE    // no repeat
gl.REPEAT           // tile
gl.MIRRORED_REPEAT  // mirror tile
```

Parameters order: `(minFilter, magFilter, wrapS, wrapT)`.

Use `cc.sys.isNative` to branch between JSB file utilities and localStorage:

```typescript
class SaveSystem {
    private static readonly SAVE_FILE = 'save_data.json';
    private static readonly STORAGE_KEY = 'save_data';

    static save(data: object): void {
        const json = JSON.stringify(data);
        if (cc.sys.isNative) {
            const path = cc.path.join(jsb.fileUtils.getWritablePath(), SaveSystem.SAVE_FILE);
            jsb.fileUtils.writeStringToFile(json, path);
            cc.log('Saved to file:', path);
        } else {
            cc.sys.localStorage.setItem(SaveSystem.STORAGE_KEY, json);
            cc.log('Saved to localStorage');
        }
    }

    static load<T>(defaultValue: T): T {
        let raw: string | null = null;
        if (cc.sys.isNative) {
            const path = cc.path.join(jsb.fileUtils.getWritablePath(), SaveSystem.SAVE_FILE);
            if (jsb.fileUtils.isFileExist(path)) {
                raw = jsb.fileUtils.getStringFromFile(path);
            }
        } else {
            raw = cc.sys.localStorage.getItem(SaveSystem.STORAGE_KEY);
        }
        if (!raw) return defaultValue;
        try {
            return JSON.parse(raw) as T;
        } catch (e) {
            cc.error('Failed to parse save data:', e);
            return defaultValue;
        }
    }

    static deleteSave(): void {
        if (cc.sys.isNative) {
            const path = cc.path.join(jsb.fileUtils.getWritablePath(), SaveSystem.SAVE_FILE);
            jsb.fileUtils.removeFile(path);
        } else {
            cc.sys.localStorage.removeItem(SaveSystem.STORAGE_KEY);
        }
    }
}
```

