class AdManager {
    private static readonly AD_SHOWN_KEY = 'last_ad_shown';
    private static readonly AD_INTERVAL_MS = 180000; // 3 minutes

    showInterstitial(): void {
        if (!this.shouldShowAd()) return;

        if (cc.sys.isNative) {
            this.showNativeAd();
        } else {
            this.showWebAd();
        }

        cc.sys.localStorage.setItem(
            AdManager.AD_SHOWN_KEY,
            Date.now().toString()
        );
    }

    private shouldShowAd(): boolean {
        const raw = cc.sys.localStorage.getItem(AdManager.AD_SHOWN_KEY);
        if (!raw) return true;
        const lastShown = parseInt(raw, 10);
        return (Date.now() - lastShown) >= AdManager.AD_INTERVAL_MS;
    }

    private showNativeAd(): void {
        if (cc.sys.platform === cc.sys.ANDROID) {
            cc.log('Showing Android interstitial');
            // jsb.reflection.callStaticMethod('com/game/AdBridge', 'showInterstitial', '()V');
        } else if (cc.sys.platform === cc.sys.IPHONE || cc.sys.platform === cc.sys.IPAD) {
            cc.log('Showing iOS interstitial');
            // jsb.reflection.callStaticMethod('AdBridge', 'showInterstitial');
        }
    }

    private showWebAd(): void {
        cc.log('Showing web ad overlay');
        cc.sys.openURL('javascript:void(0)'); // placeholder
        // In practice, call your web ad SDK
    }
}
```

The manager checks a cooldown stored in localStorage, then dispatches to the appropriate native or web ad implementation based on `cc.sys.isNative` and `cc.sys.platform`.

`cc.assert` logs an error if the condition is falsy:

```typescript
cc.assert(...args: any[]): void
```

Examples:
```typescript
// Basic assertion
cc.assert(health >= 0, 'Health cannot be negative');

// Validate function parameters
function setSpeed(speed: number): void {
    cc.assert(cc.isNumber(speed), 'Speed must be a number');
    cc.assert(speed >= 0, 'Speed must be non-negative');
    this._speed = speed;
}

// Validate object state
class Player {
    private _sprite: cc.Sprite | null = null;

    init(spritePath: string): void {
        this._sprite = new cc.Sprite(spritePath);
        cc.assert(cc.sys.isObjectValid(this._sprite), 'Failed to create player sprite');
    }

    attack(): void {
        cc.assert(this._sprite !== null, 'Player not initialized');
        // proceed with attack...
    }
}

// Validate configuration
function loadConfig(config: any): void {
    cc.assert(cc.isObject(config), 'Config must be an object');
    cc.assert(cc.isNumber(config.width), 'Config.width must be a number');
    cc.assert(cc.isNumber(config.height), 'Config.height must be a number');
}
```

Unlike `console.assert`, `cc.assert` uses the engine's error logging system and works consistently across native and H5 platforms.

Here's a complete example with custom uniforms:

```typescript
class ShaderEffect {
    private _program: cc.GLProgram;
    private _timeLoc: WebGLUniformLocation;

    apply(sprite: cc.Sprite): void {
        const vertSrc = `
            attribute vec4 a_position;
            attribute vec2 a_texCoord;
            varying vec2 v_texCoord;
            void main() {
                gl_Position = CC_PMatrix * CC_MVMatrix * a_position;
                v_texCoord = a_texCoord;
            }
        `;

        const fragSrc = `
            precision mediump float;
            varying vec2 v_texCoord;
            uniform sampler2D CC_Texture0;
            uniform float u_time;
            void main() {
                vec2 uv = v_texCoord;
                uv.x += sin(uv.y * 10.0 + u_time) * 0.02;
                gl_FragColor = texture2D(CC_Texture0, uv);
            }
        `;

        this._program = new cc.GLProgram();
        this._program.initWithString(vertSrc, fragSrc);
        this._program.addAttribute(cc.ATTRIBUTE_NAME_POSITION, cc.VERTEX_ATTRIB_POSITION);
        this._program.addAttribute(cc.ATTRIBUTE_NAME_TEX_COORD, cc.VERTEX_ATTRIB_TEX_COORDS);
        this._program.link();
        this._program.updateUniforms();

        // Get uniform location
        this._timeLoc = this._program.getUniformLocationForName('u_time');

        // Apply to sprite
        sprite.setShaderProgram(this._program);
    }

    update(dt: number, elapsed: number): void {
        this._program.use();
        this._program.setUniformLocationWith1f(this._timeLoc, elapsed);
    }
}
```

The workflow: create program, init with shaders, add attributes, link, get uniform locations, then update uniforms each frame.

instruction:
Find and fix the bug in this localStorage code:

```typescript
class InventoryManager {
    private _items: string[] = [];

    save(): void {
        cc.sys.localStorage.setItem('inventory', this._items);
    }

    load(): void {
        this._items = cc.sys.localStorage.getItem('inventory');
    }
}
```

output:
Two bugs:

**Bug 1: `setItem` receives an array instead of a string.** `setItem` expects `string | number`. Passing an array results in it being converted to a comma-separated string like `"sword,shield,potion"`, losing array structure.

**Bug 2: `getItem` returns `string | null | undefined`, not `string[]`.** Assigning directly to `_items` is a type error and won't produce an array.

Fixed code:
```typescript
class InventoryManager {
    private _items: string[] = [];
    private static readonly STORAGE_KEY = 'inventory';

    save(): void {
        const json = JSON.stringify(this._items);
        cc.sys.localStorage.setItem(InventoryManager.STORAGE_KEY, json);
    }

    load(): void {
        const raw = cc.sys.localStorage.getItem(InventoryManager.STORAGE_KEY);
        if (!raw) {
            this._items = [];
            return;
        }
        try {
            const parsed = JSON.parse(raw);
            this._items = cc.isArray(parsed) ? parsed : [];
        } catch (e) {
            cc.error('Failed to parse inventory data');
            this._items = [];
        }
    }
}
```

Always use `JSON.stringify` for complex types and `JSON.parse` with error handling when reading back.

`cc.sys.dump()` outputs system information to the console for debugging:

```typescript
cc.sys.dump(): void  // JSB only
```

Call it during development to inspect the runtime environment:

```typescript
// Debug helper — call on game start
function logSystemInfo(): void {
    cc.log('=== System Info ===');
    cc.log('Platform:', cc.sys.platform);
    cc.log('OS:', cc.sys.os);
    cc.log('Is Native:', cc.sys.isNative);
    cc.log('Is Mobile:', cc.sys.isMobile);
    cc.log('Language:', cc.sys.language);

    if (!cc.sys.isNative) {
        cc.log('Browser:', cc.sys.browserType, cc.sys.browserVersion);
        cc.log('Window:', cc.sys.windowPixelResolution.width, 'x', cc.sys.windowPixelResolution.height);
    }

    cc.log('Capabilities:');
    cc.log('  OpenGL:', cc.sys.capabilities.opengl);
    cc.log('  Touch:', cc.sys.capabilities.touches);
    cc.log('  Keyboard:', cc.sys.capabilities.keyboard);
    cc.log('  Mouse:', cc.sys.capabilities.mouse);
    cc.log('  Accelerometer:', cc.sys.capabilities.accelerometer);

    // JSB dump for native platforms
    if (cc.sys.isNative) {
        cc.sys.dump();
    }
}
```

`cc.sys.dump()` is a JSB-only method that prints internal engine state. Use the manual logging approach above for cross-platform debugging.

Combine `cc.sys.language` for auto-detection with localStorage for user preference:

```typescript
interface LocaleStrings {
    [key: string]: string;
}

class Localization {
    private static readonly LANG_KEY = 'user_language';
    private _strings: LocaleStrings = {};
    private _currentLang: string;

    private static readonly SUPPORTED_LANGS = ['en', 'zh', 'ja', 'ko', 'es', 'fr'];

    constructor() {
        this._currentLang = this.detectLanguage();
        this.loadStrings(this._currentLang);
    }

    private detectLanguage(): string {
        // Check user preference first
        const saved = cc.sys.localStorage.getItem(Localization.LANG_KEY);
        if (saved && Localization.SUPPORTED_LANGS.indexOf(saved) >= 0) {
            return saved;
        }
        // Fall back to system language
        const sysLang = cc.sys.language as string;
        if (Localization.SUPPORTED_LANGS.indexOf(sysLang) >= 0) {
            return sysLang;
        }
        return 'en';
    }

    private loadStrings(lang: string): void {
        const path = cc.path.join('res', 'i18n', lang + '.json');
        cc.loader.loadJson(path, (err, data) => {
            if (err) {
                cc.warn('Failed to load language:', lang, '- falling back to en');
                if (lang !== 'en') this.loadStrings('en');
                return;
            }
            this._strings = data;
        });
    }

    setLanguage(lang: string): void {
        this._currentLang = lang;
        cc.sys.localStorage.setItem(Localization.LANG_KEY, lang);
        this.loadStrings(lang);
    }

    get(key: string): string {
        return this._strings[key] || key;
    }

    get currentLanguage(): string {
        return this._currentLang;
    }
}
```

