`cc.sys.restartVM()` restarts the JavaScript virtual machine on native (JSB) platforms:

```typescript
cc.sys.restartVM(): void  // JSB only, no-op on H5
```

This completely resets the JS runtime, re-executing all scripts from scratch. Use cases:

```typescript
// Hot reload during development
function devReload(): void {
    if (cc.sys.isNative) {
        cc.log('Restarting VM for hot reload...');
        cc.sys.restartVM();
    } else {
        // On web, just reload the page
        window.location.reload();
    }
}

// Recovery from unrecoverable error
function handleFatalError(error: Error): void {
    cc.error('Fatal error:', error.message);
    // Save state first
    cc.sys.localStorage.setItem('crash_recovery', 'true');
    if (cc.sys.isNative) {
        cc.sys.restartVM();
    }
}

// Language change that requires full restart
function changeLanguage(lang: string): void {
    cc.sys.localStorage.setItem('language', lang);
    if (cc.sys.isNative) {
        cc.sys.restartVM(); // restart to reload all assets in new language
    }
}
```

**Warning:** This destroys ALL JavaScript state — all variables, objects, listeners, and timers are lost. Only use as a last resort. Always save critical state to localStorage before calling.

Additive blending makes overlapping colors brighter, perfect for fire, explosions, and glow effects:

```typescript
// Additive blend: output = src_color * 1 + dst_color * 1
const additiveBlend = new cc.BlendFunc(cc.ONE, cc.ONE);

// Apply to a particle system
const particles = new cc.ParticleSystem('res/fire.plist');
particles.setBlendFunc(additiveBlend);
parentNode.addChild(particles);

// Apply to a glow sprite
const glowSprite = new cc.Sprite('res/glow.png');
glowSprite.setBlendFunc(new cc.BlendFunc(cc.ONE, cc.ONE));
glowSprite.setPosition(200, 200);
parentNode.addChild(glowSprite);

// Softer additive (uses source alpha for transparency)
const softAdditive = new cc.BlendFunc(cc.SRC_ALPHA, cc.ONE);
const softGlow = new cc.Sprite('res/soft_glow.png');
softGlow.setBlendFunc(softAdditive);

// Creating a layered glow effect
function createGlowEffect(position: cc.Point): cc.Node {
    const container = new cc.Node();
    container.setPosition(position);

    // Base glow (large, dim)
    const outer = new cc.Sprite('res/glow_circle.png');
    outer.setBlendFunc(new cc.BlendFunc(cc.SRC_ALPHA, cc.ONE));
    outer.setScale(2.0);
    outer.setOpacity(100);
    container.addChild(outer);

    // Core glow (small, bright)
    const inner = new cc.Sprite('res/glow_circle.png');
    inner.setBlendFunc(new cc.BlendFunc(cc.ONE, cc.ONE));
    inner.setScale(0.5);
    container.addChild(inner);

    return container;
}
```

Check `cc.sys.capabilities.keyboard` before registering:

```typescript
class InputManager {
    private _keyListener: cc.EventListener | null = null;

    setupKeyboard(node: cc.Node): boolean {
        if (!cc.sys.capabilities.keyboard) {
            cc.log('Keyboard not available on this platform');
            return false;
        }

        this._keyListener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (keyCode: cc.KEY, event: cc.Event): void => {
                this.handleKeyDown(keyCode);
            },
            onKeyReleased: (keyCode: cc.KEY, event: cc.Event): void => {
                this.handleKeyUp(keyCode);
            }
        }, node);

        cc.log('Keyboard input enabled');
        return true;
    }

    cleanup(): void {
        if (this._keyListener) {
            cc.eventManager.removeListener(this._keyListener);
            this._keyListener = null;
        }
    }
}

// In your layer:
onEnter(): void {
    super.onEnter();
    const input = new InputManager();
    if (!input.setupKeyboard(this)) {
        // Keyboard not available — show virtual controls
        this.createVirtualDPad();
    }
}
```

`cc.sys.capabilities.keyboard` is `true` on desktop platforms (native and browser) and `false` on mobile platforms (unless an external keyboard is connected, which isn't detected).

```typescript
cc.path.join(...args: string[]): string
```

Accepts any number of string segments and joins them with `/`:

```typescript
// Basic usage
cc.path.join('res', 'hero', 'hero.png')  // 'res/hero/hero.png'
cc.path.join('res', 'audio')              // 'res/audio'
cc.path.join('a', 'b', 'c', 'd.txt')     // 'a/b/c/d.txt'

// Single argument
