Related `cc.path` methods:
```typescript
cc.path.extname(pathStr: string): string     // '.png'
cc.path.basename(pathStr: string, ext: string): string  // 'hero'
cc.path.dirname(pathStr: string): string     // 'res/hero'
```

All return `string` types. `extname` includes the dot. `basename` removes the provided extension. `dirname` returns everything before the last separator.

Use a basic XOR cipher (for obfuscation, not security-critical encryption):

```typescript
class SecureStorage {
    private static readonly CIPHER_KEY = 'c0c0s_g4m3_k3y';

    private static xorCipher(input: string, key: string): string {
        let result = '';
        for (let i = 0; i < input.length; i++) {
            const charCode = input.charCodeAt(i) ^ key.charCodeAt(i % key.length);
            result += String.fromCharCode(charCode);
        }
        return result;
    }

    private static encode(plain: string): string {
        const ciphered = SecureStorage.xorCipher(plain, SecureStorage.CIPHER_KEY);
        // Convert to base64 for safe storage
        return btoa(ciphered);
    }

    private static decode(encoded: string): string {
        const ciphered = atob(encoded);
        return SecureStorage.xorCipher(ciphered, SecureStorage.CIPHER_KEY);
    }

    static setItem(key: string, value: string): void {
        const encoded = SecureStorage.encode(value);
        cc.sys.localStorage.setItem(key, encoded);
    }

    static getItem(key: string): string | null {
        const raw = cc.sys.localStorage.getItem(key);
        if (!raw) return null;
        try {
            return SecureStorage.decode(raw);
        } catch (e) {
            cc.error('Failed to decode secure storage for key:', key);
            return null;
        }
    }

    static setJSON<T>(key: string, data: T): void {
        SecureStorage.setItem(key, JSON.stringify(data));
    }

    static getJSON<T>(key: string, defaultValue: T): T {
        const raw = SecureStorage.getItem(key);
        if (!raw) return defaultValue;
        try {
            return JSON.parse(raw) as T;
        } catch (e) {
            return defaultValue;
        }
    }
}

// Usage:
SecureStorage.setJSON('player_coins', { amount: 9999 });
const coins = SecureStorage.getJSON('player_coins', { amount: 0 });
```

Note: XOR is obfuscation only. For real security, use a proper encryption library.

instruction:
Find and fix the bug in this shader code:

```typescript
const program = new cc.GLProgram();
program.initWithString(vertSrc, fragSrc);
program.link();
program.updateUniforms();
sprite.setShaderProgram(program);
```

output:
The bug is that **attributes are not added before linking**. Without calling `addAttribute`, the shader won't know how to bind vertex data (positions, texture coordinates), resulting in a black or invisible sprite.

Fixed code:
```typescript
const program = new cc.GLProgram();
program.initWithString(vertSrc, fragSrc);

// FIX: Add attributes BEFORE linking
program.addAttribute(cc.ATTRIBUTE_NAME_POSITION, cc.VERTEX_ATTRIB_POSITION);
program.addAttribute(cc.ATTRIBUTE_NAME_TEX_COORD, cc.VERTEX_ATTRIB_TEX_COORDS);

program.link();
program.updateUniforms();
sprite.setShaderProgram(program);
```

The correct order is:
1. `initWithString(vert, frag)` — compile shaders
2. `addAttribute(name, index)` — bind attribute locations
3. `link()` — link the program
4. `updateUniforms()` — set up built-in uniforms
5. Apply to node

If your shader also uses vertex colors, add that attribute too:
```typescript
program.addAttribute(cc.ATTRIBUTE_NAME_COLOR, cc.VERTEX_ATTRIB_COLOR);
```

`cc.sys.localStorage.clear()` removes ALL stored key-value pairs:

```typescript
cc.sys.localStorage.clear(): void
```

This is destructive — use it carefully:

```typescript
// DANGEROUS: clears everything
cc.sys.localStorage.clear();

// Safer approach: selective clearing
class StorageManager {
    private static readonly GAME_KEYS = [
        'highscore', 'level', 'inventory', 'settings'
    ];
    private static readonly PROTECTED_KEYS = ['device_id', 'first_launch'];

    static clearGameData(): void {
        // Only clear game-related keys, preserve system keys
        for (const key of StorageManager.GAME_KEYS) {
            cc.sys.localStorage.removeItem(key);
        }
        cc.log('Game data cleared');
    }

    static fullReset(): void {
        // Confirm before clearing everything
        cc.log('Performing full storage reset');
        cc.sys.localStorage.clear();
    }

    static resetWithBackup(): void {
        // Save protected data
        const backups: { [key: string]: string } = {};
        for (const key of StorageManager.PROTECTED_KEYS) {
            const val = cc.sys.localStorage.getItem(key);
            if (val) backups[key] = val;
        }

        // Clear all
        cc.sys.localStorage.clear();

        // Restore protected keys
        for (const key in backups) {
            cc.sys.localStorage.setItem(key, backups[key]);
        }
    }
}
```

Prefer `removeItem` for specific keys over `clear()` to avoid accidentally deleting important data.

Use `cc.sys.windowPixelResolution` which is available in browser builds:

```typescript
if (!cc.sys.isNative) {
    const resolution: cc.Size = cc.sys.windowPixelResolution;
    cc.log('Pixel width:', resolution.width);
    cc.log('Pixel height:', resolution.height);
}
```

Practical example — responsive design:
```typescript
function configureForScreen(): void {
    if (cc.sys.isNative) {
        // Use design resolution on native
        const winSize = cc.director.getWinSize();
        cc.log('Design size:', winSize.width, 'x', winSize.height);
        return;
    }

    const pixelRes = cc.sys.windowPixelResolution;
    const aspectRatio = pixelRes.width / pixelRes.height;

    if (aspectRatio > 1.7) {
        // Wide screen (16:9 or wider)
        cc.log('Wide screen layout');
    } else if (aspectRatio > 1.3) {
        // Standard screen (4:3 to 16:10)
        cc.log('Standard layout');
    } else {
        // Tall screen (portrait or near-square)
        cc.log('Tall screen layout');
    }

    // High-DPI detection
    const designSize = cc.director.getWinSize();
    const dpr = pixelRes.width / designSize.width;
    if (dpr > 1.5) {
        cc.log('High-DPI display, use HD assets');
    }
}
```

Note: `cc.sys.windowPixelResolution` is `null`/unavailable on native platforms. Always check `cc.sys.isNative` first.

Use `getUniformLocationForName` to get the location, then `setUniformLocationWith4f` to set RGBA values:

```typescript
class ColorShaderSprite extends cc.Sprite {
    private _program: cc.GLProgram;
    private _colorLoc: WebGLUniformLocation;

    constructor(filename: string) {
        super(filename);
        this.initColorShader();
    }

    private initColorShader(): void {
        const fragSrc = `
            precision mediump float;
            varying vec2 v_texCoord;
            uniform sampler2D CC_Texture0;
            uniform vec4 u_overlayColor;
            void main() {
                vec4 tex = texture2D(CC_Texture0, v_texCoord);
                gl_FragColor = mix(tex, u_overlayColor, u_overlayColor.a) * vec4(1.0, 1.0, 1.0, tex.a);
            }
        `;

        this._program = new cc.GLProgram();
        this._program.initWithString(DEFAULT_VERT, fragSrc);
        this._program.addAttribute(cc.ATTRIBUTE_NAME_POSITION, cc.VERTEX_ATTRIB_POSITION);
        this._program.addAttribute(cc.ATTRIBUTE_NAME_TEX_COORD, cc.VERTEX_ATTRIB_TEX_COORDS);
        this._program.link();
        this._program.updateUniforms();

        this._colorLoc = this._program.getUniformLocationForName('u_overlayColor');
        this.setShaderProgram(this._program);
    }

    setOverlayColor(r: number, g: number, b: number, intensity: number): void {
        this._program.use();
        this._program.setUniformLocationWith4f(this._colorLoc, r, g, b, intensity);
    }
}

// Usage:
const sprite = new ColorShaderSprite('res/hero.png');
sprite.setOverlayColor(1.0, 0.0, 0.0, 0.5); // 50% red overlay
```

The `4f` suffix means four float values (r, g, b, a). Other variants: `1f` (one float), `2f` (two floats).

Create a silhouette by zeroing out the source color and using only the destination:

```typescript
// Method 1: Use a shader to force black color, then normal blend
class SilhouetteSprite extends cc.Sprite {
    constructor(filename: string) {
        super(filename);
        this.initSilhouetteShader();
    }

    private initSilhouetteShader(): void {
        const fragSrc = `
            precision mediump float;
            varying vec2 v_texCoord;
            uniform sampler2D CC_Texture0;
            uniform vec4 u_shadowColor;
            void main() {
                vec4 tex = texture2D(CC_Texture0, v_texCoord);
                gl_FragColor = vec4(u_shadowColor.rgb, tex.a * u_shadowColor.a);
            }
        `;

        const program = new cc.GLProgram();
        program.initWithString(DEFAULT_VERT, fragSrc);
        program.addAttribute(cc.ATTRIBUTE_NAME_POSITION, cc.VERTEX_ATTRIB_POSITION);
        program.addAttribute(cc.ATTRIBUTE_NAME_TEX_COORD, cc.VERTEX_ATTRIB_TEX_COORDS);
        program.link();
        program.updateUniforms();
        this.setShaderProgram(program);

        // Set shadow color (dark, semi-transparent)
        const state = this.getGLProgramState();
        state.setUniformVec4('u_shadowColor', { x: 0.0, y: 0.0, z: 0.0, w: 0.5 });
    }
}

// Method 2: Simple approach using setColor + blend
function createSimpleShadow(originalSprite: cc.Sprite): cc.Sprite {
    const shadow = new cc.Sprite(originalSprite.getTexture());
    shadow.setColor(cc.color(0, 0, 0));
    shadow.setOpacity(80);
    shadow.setBlendFunc(new cc.BlendFunc(cc.SRC_ALPHA, cc.ONE_MINUS_SRC_ALPHA));
    shadow.setPosition(originalSprite.x + 5, originalSprite.y - 5);
    shadow.setScale(originalSprite.getScale());
    return shadow;
}
```

Use a scheduled callback combined with localStorage:

```typescript
class AutoSaveManager {
    private _node: cc.Node;
    private _getData: () => object;
    private _dirty: boolean = false;
    private static readonly SAVE_KEY = 'autosave';
    private static readonly SAVE_INTERVAL = 30; // seconds

    constructor(node: cc.Node, getData: () => object) {
        this._node = node;
        this._getData = getData;
    }

    start(): void {
        // Periodic auto-save
        this._node.schedule(() => {
            if (this._dirty) {
                this.save();
            }
        }, AutoSaveManager.SAVE_INTERVAL);

        cc.log('Auto-save started, interval:', AutoSaveManager.SAVE_INTERVAL, 's');
    }

    markDirty(): void {
        this._dirty = true;
    }

    save(): void {
        const data = this._getData();
        const json = JSON.stringify(data);
        cc.sys.localStorage.setItem(AutoSaveManager.SAVE_KEY, json);
        cc.sys.localStorage.setItem(AutoSaveManager.SAVE_KEY + '_time', Date.now().toString());
        this._dirty = false;
        cc.log('Auto-saved at', new Date().toISOString());
    }

    load<T>(defaultValue: T): T {
        const raw = cc.sys.localStorage.getItem(AutoSaveManager.SAVE_KEY);
        if (!raw) return defaultValue;
        try {
            return JSON.parse(raw) as T;
        } catch (e) {
            cc.error('Corrupt auto-save, using default');
            return defaultValue;
        }
    }

    getLastSaveTime(): number {
        const raw = cc.sys.localStorage.getItem(AutoSaveManager.SAVE_KEY + '_time');
        return raw ? parseInt(raw, 10) : 0;
    }

    stop(): void {
        this._node.unscheduleAllCallbacks();
        if (this._dirty) this.save(); // final save
    }
}
```

```typescript
cc.sys.openURL(url: string): void
```

Parameters:
- **`url`** — `string` containing the URL to open. Must be a valid URL including the protocol (e.g., `https://`).

Return type: `void`

Behavior:
- **Native (JSB):** Opens the URL in the device's default browser app, switching away from the game
- **HTML5:** Opens the URL in a new browser tab/window

Examples:
```typescript
// Open website
cc.sys.openURL('https://www.example.com');

// Open app store based on platform
function rateApp(): void {
    if (cc.sys.os === cc.sys.OS_IOS) {
        cc.sys.openURL('https://apps.apple.com/app/id123456');
    } else if (cc.sys.os === cc.sys.OS_ANDROID) {
        cc.sys.openURL('market://details?id=com.example.game');
    }
}

// Open email
cc.sys.openURL('mailto:support@example.com?subject=Bug Report');

// Social media
cc.sys.openURL('https://twitter.com/intent/tweet?text=Playing%20MyGame!');
```

Note: On native platforms, the game continues running in the background. On some devices, the OS may pause or terminate the game when switching to the browser.

Use platform detection combined with `cc.director.getSafeAreaRect()` (if available) or manual offsets:

```typescript
class SafeAreaHelper {
    static getInsets(): { top: number; bottom: number; left: number; right: number } {
        const winSize = cc.director.getWinSize();
        const defaults = { top: 0, bottom: 0, left: 0, right: 0 };

        if (!cc.sys.isMobile) return defaults;

        // Try safe area rect from director
        const safeRect = cc.director.getSafeAreaRect();
        if (safeRect) {
            return {
                left: safeRect.x,
                bottom: safeRect.y,
                right: winSize.width - (safeRect.x + safeRect.width),
                top: winSize.height - (safeRect.y + safeRect.height)
            };
        }

        // Fallback: estimate based on platform
        if (cc.sys.platform === cc.sys.IPHONE) {
            return { top: 44, bottom: 34, left: 0, right: 0 };
        }

        return defaults;
    }

    static adjustUI(node: cc.Node): void {
        const insets = SafeAreaHelper.getInsets();
        const winSize = cc.director.getWinSize();

        // Position UI elements within safe area
        const safeWidth = winSize.width - insets.left - insets.right;
        const safeHeight = winSize.height - insets.top - insets.bottom;
        const safeCenterX = insets.left + safeWidth / 2;
        const safeCenterY = insets.bottom + safeHeight / 2;

        node.setPosition(safeCenterX, safeCenterY);
        cc.log('Safe area:', safeWidth, 'x', safeHeight);
    }
}
```

