```typescript
class DebugOverlay extends cc.Layer {
    private _infoLabel: cc.LabelTTF;
    private _fpsLabel: cc.LabelTTF;
    private _frameCount: number = 0;
    private _elapsed: number = 0;
    private static readonly UPDATE_INTERVAL = 1.0;

    onEnter(): void {
        super.onEnter();
        const winSize = cc.director.getWinSize();

        this._infoLabel = new cc.LabelTTF(this.buildInfoText(), 'Courier', 12);
        this._infoLabel.setAnchorPoint(0, 1);
        this._infoLabel.setPosition(10, winSize.height - 10);
        this.addChild(this._infoLabel);

        this._fpsLabel = new cc.LabelTTF('FPS: --', 'Courier', 14);
        this._fpsLabel.setAnchorPoint(1, 1);
        this._fpsLabel.setPosition(winSize.width - 10, winSize.height - 10);
        this.addChild(this._fpsLabel);

        this.scheduleUpdate();
    }

    private buildInfoText(): string {
        const lines: string[] = [];
        lines.push('Platform: ' + cc.sys.platform);
        lines.push('OS: ' + cc.sys.os);
        lines.push('Native: ' + cc.sys.isNative);
        lines.push('Mobile: ' + cc.sys.isMobile);
        lines.push('Language: ' + cc.sys.language);

        if (!cc.sys.isNative) {
            lines.push('Browser: ' + (cc.sys.browserType || 'N/A'));
            const res = cc.sys.windowPixelResolution;
            lines.push('Window: ' + res.width + 'x' + res.height);
        }

        const caps = cc.sys.capabilities;
        lines.push('Touch: ' + caps.touches);
        lines.push('Keyboard: ' + caps.keyboard);
        lines.push('Mouse: ' + caps.mouse);
        lines.push('Accelerometer: ' + caps.accelerometer);

        return lines.join('\n');
    }

    update(dt: number): void {
        this._frameCount++;
        this._elapsed += dt;
        if (this._elapsed >= DebugOverlay.UPDATE_INTERVAL) {
            const fps = Math.round(this._frameCount / this._elapsed);
            this._fpsLabel.setString('FPS: ' + fps);
            this._frameCount = 0;
            this._elapsed = 0;
        }
    }
}
```

Wrap localStorage calls with error handling for quota and availability:

```typescript
class SafeStorage {
    private static _available: boolean | null = null;

    static isAvailable(): boolean {
        if (SafeStorage._available !== null) return SafeStorage._available;
        try {
            const testKey = '__storage_test__';
            cc.sys.localStorage.setItem(testKey, 'test');
            cc.sys.localStorage.removeItem(testKey);
            SafeStorage._available = true;
        } catch (e) {
            cc.warn('localStorage not available:', e);
            SafeStorage._available = false;
        }
        return SafeStorage._available;
    }

    static setItem(key: string, value: string): boolean {
        if (!SafeStorage.isAvailable()) return false;
        try {
            cc.sys.localStorage.setItem(key, value);
            return true;
        } catch (e) {
            cc.error('Storage full or write failed for key:', key);
            // Try to free space by removing non-essential data
            SafeStorage.freeSpace();
            try {
                cc.sys.localStorage.setItem(key, value);
                return true;
            } catch (e2) {
                cc.error('Storage still full after cleanup');
                return false;
            }
        }
    }

    static getItem(key: string): string | null {
        if (!SafeStorage.isAvailable()) return null;
        try {
            const val = cc.sys.localStorage.getItem(key);
            return val !== undefined ? val : null;
        } catch (e) {
            cc.error('Failed to read key:', key);
            return null;
        }
    }

    private static readonly NON_ESSENTIAL_KEYS = ['debug_log', 'analytics_cache'];

    private static freeSpace(): void {
        for (const key of SafeStorage.NON_ESSENTIAL_KEYS) {
            cc.sys.localStorage.removeItem(key);
        }
    }
}
```

Use `setUniformLocationWith2f` to pass two float values (e.g., resolution, offset) to a shader:

```typescript
class RippleEffect {
    private _program: cc.GLProgram;
    private _centerLoc: WebGLUniformLocation;
    private _timeLoc: WebGLUniformLocation;

    apply(sprite: cc.Sprite): void {
        const fragSrc = `
            precision mediump float;
            varying vec2 v_texCoord;
            uniform sampler2D CC_Texture0;
            uniform vec2 u_center;
            uniform float u_time;
            void main() {
                vec2 uv = v_texCoord;
                float dist = distance(uv, u_center);
                float ripple = sin(dist * 30.0 - u_time * 5.0) * 0.01;
                uv += normalize(uv - u_center) * ripple;
                gl_FragColor = texture2D(CC_Texture0, uv);
            }
        `;

        this._program = new cc.GLProgram();
        this._program.initWithString(DEFAULT_VERT, fragSrc);
        this._program.addAttribute(cc.ATTRIBUTE_NAME_POSITION, cc.VERTEX_ATTRIB_POSITION);
        this._program.addAttribute(cc.ATTRIBUTE_NAME_TEX_COORD, cc.VERTEX_ATTRIB_TEX_COORDS);
        this._program.link();
        this._program.updateUniforms();

        this._centerLoc = this._program.getUniformLocationForName('u_center');
        this._timeLoc = this._program.getUniformLocationForName('u_time');
        sprite.setShaderProgram(this._program);

        // Set center to middle of texture
        this._program.use();
        this._program.setUniformLocationWith2f(this._centerLoc, 0.5, 0.5);
    }

    update(elapsed: number, centerX: number, centerY: number): void {
        this._program.use();
        this._program.setUniformLocationWith1f(this._timeLoc, elapsed);
        this._program.setUniformLocationWith2f(this._centerLoc, centerX, centerY);
    }
}
```

`setUniformLocationWith2f(loc, f1, f2)` maps to `vec2` in GLSL. Also available: `1f` for `float`, `4f` for `vec4`.

Use `cc.sys.platform === cc.sys.IPAD`:

```typescript
// Direct platform check
if (cc.sys.platform === cc.sys.IPAD) {
    cc.log('Running on iPad native');
}

// Check for all iOS devices
function isIOSDevice(): boolean {
    return cc.sys.platform === cc.sys.IPHONE ||
           cc.sys.platform === cc.sys.IPAD;
}

// Or use OS check (includes iOS browsers too)
function isIOSAny(): boolean {
    return cc.sys.os === cc.sys.OS_IOS; // 'iOS'
}

// Adapt UI for iPad's larger screen
function setupUI(): void {
    if (cc.sys.platform === cc.sys.IPAD) {
        // iPad: larger UI elements, side panel layout
        cc.log('iPad layout');
    } else if (cc.sys.platform === cc.sys.IPHONE) {
        // iPhone: compact layout
        cc.log('iPhone layout');
    } else if (cc.sys.isMobile) {
        // Other mobile (Android)
        cc.log('Mobile layout');
    } else {
        // Desktop
        cc.log('Desktop layout');
    }
}
```

Key: `cc.sys.IPAD` (5) is distinct from `cc.sys.IPHONE` (4). Both have `cc.sys.os === cc.sys.OS_IOS`.

Build a helper that applies common texture configurations:

```typescript
class TextureHelper {
    static applyPixelArt(texture: cc.Texture2D): void {
        // No interpolation — sharp pixels
        texture.setTexParameters(gl.NEAREST, gl.NEAREST, gl.CLAMP_TO_EDGE, gl.CLAMP_TO_EDGE);
    }

    static applySmooth(texture: cc.Texture2D): void {
        // Bilinear filtering — smooth scaling
        texture.setTexParameters(gl.LINEAR, gl.LINEAR, gl.CLAMP_TO_EDGE, gl.CLAMP_TO_EDGE);
    }

    static applyTiled(texture: cc.Texture2D): void {
        // Repeat pattern — for backgrounds
        texture.setTexParameters(gl.LINEAR, gl.LINEAR, gl.REPEAT, gl.REPEAT);
    }

    static applyMirrored(texture: cc.Texture2D): void {
        // Mirror repeat — seamless tiling
        texture.setTexParameters(gl.LINEAR, gl.LINEAR, gl.MIRRORED_REPEAT, gl.MIRRORED_REPEAT);
    }

    static applyTrilinear(texture: cc.Texture2D): void {
        // Highest quality with mipmaps
        texture.setTexParameters(
            gl.LINEAR_MIPMAP_LINEAR,
            gl.LINEAR,
            gl.CLAMP_TO_EDGE,
            gl.CLAMP_TO_EDGE
        );
    }
}

// Usage:
const tex = cc.textureCache.addImage('res/pixel_hero.png');
TextureHelper.applyPixelArt(tex);

const bgTex = cc.textureCache.addImage('res/grass_tile.png');
TextureHelper.applyTiled(bgTex);

// Set parameters: (minFilter, magFilter, wrapS, wrapT)
// minFilter: used when texture is scaled down
// magFilter: used when texture is scaled up
// wrapS: horizontal wrapping
// wrapT: vertical wrapping
```

instruction:
Find and fix the bug in this platform-specific code:

```typescript
function getStoragePath(): string {
    if (cc.sys.isNative) {
        return jsb.fileUtils.getWritablePath();
    }
    return cc.sys.localStorage;
}
```

output:
Bug: the function claims to return `string` but the else branch returns `cc.sys.localStorage`, which is an **object** (the localStorage interface), not a string path.

The function conflates two different concepts: a file system path (native) and a storage API object (web).

Fixed code — if the intent is to get a writable path:
```typescript
function getWritablePath(): string {
    if (cc.sys.isNative) {
        return jsb.fileUtils.getWritablePath();
    }
    // Web has no file system path; return empty or a logical prefix
    return '';
}
```

Fixed code — if the intent is to get a storage interface:
```typescript
interface StorageAdapter {
    save(key: string, value: string): void;
    load(key: string): string | null;
}

function getStorage(): StorageAdapter {
    if (cc.sys.isNative) {
        return {
            save: (key, value) => {
                const path = cc.path.join(jsb.fileUtils.getWritablePath(), key + '.dat');
                jsb.fileUtils.writeStringToFile(value, path);
            },
            load: (key) => {
                const path = cc.path.join(jsb.fileUtils.getWritablePath(), key + '.dat');
                return jsb.fileUtils.isFileExist(path)
                    ? jsb.fileUtils.getStringFromFile(path)
                    : null;
            }
        };
    }
    return {
        save: (key, value) => cc.sys.localStorage.setItem(key, value),
        load: (key) => cc.sys.localStorage.getItem(key) || null
    };
}
```

Key lesson: don't mix return types — use a common interface.

```typescript
cc.sys.localStorage.removeItem(key: string): void
```

Removes a single key-value pair from storage.

```typescript
class ResetManager {
    private static readonly GAME_KEYS = [
        'highscore',
        'current_level',
        'inventory',
        'achievements',
        'player_profile',
        'settings'
    ] as const;

    static resetProgress(): void {
        cc.sys.localStorage.removeItem('highscore');
        cc.sys.localStorage.removeItem('current_level');
        cc.sys.localStorage.removeItem('inventory');
        cc.sys.localStorage.removeItem('achievements');
        cc.log('Progress reset');
    }

    static resetSettings(): void {
        cc.sys.localStorage.removeItem('settings');
        cc.log('Settings reset to defaults');
    }

    static resetAll(): void {
        for (const key of ResetManager.GAME_KEYS) {
            cc.sys.localStorage.removeItem(key);
        }
        cc.log('All data reset');
    }

    static resetWithConfirmation(callback: (confirmed: boolean) => void): void {
        // In practice, show a UI dialog first
        // After confirmation:
        ResetManager.resetAll();
        callback(true);
    }
}

// Usage:
ResetManager.resetProgress();  // keep settings, reset game data
ResetManager.resetAll();       // clear everything
```

Prefer targeted `removeItem` calls over `clear()` to avoid accidentally removing data from other parts of the app.

Map `cc.sys.language` values to a typed enum:

```typescript
enum AppLocale {
    EN = 'en',
    ZH = 'zh',
    JA = 'ja',
    KO = 'ko',
    ES = 'es',
    FR = 'fr',
    DE = 'de',
    RU = 'ru',
    PT = 'pt'
}

class LocaleHelper {
    private static readonly LANG_MAP: ReadonlyMap<string, AppLocale> = new Map([
        [cc.sys.LANGUAGE_ENGLISH, AppLocale.EN],
        [cc.sys.LANGUAGE_CHINESE, AppLocale.ZH],
        [cc.sys.LANGUAGE_JAPANESE, AppLocale.JA],
        [cc.sys.LANGUAGE_KOREAN, AppLocale.KO],
        [cc.sys.LANGUAGE_SPANISH, AppLocale.ES],
        [cc.sys.LANGUAGE_FRENCH, AppLocale.FR],
        [cc.sys.LANGUAGE_GERMAN, AppLocale.DE],
        [cc.sys.LANGUAGE_RUSSIAN, AppLocale.RU],
        [cc.sys.LANGUAGE_PORTUGUESE, AppLocale.PT]
    ]);

    static getSystemLocale(): AppLocale {
        const sysLang = cc.sys.language as string;
        return LocaleHelper.LANG_MAP.get(sysLang) || AppLocale.EN;
    }

    static getUserLocale(): AppLocale {
        const saved = cc.sys.localStorage.getItem('user_locale');
        if (saved && Object.values(AppLocale).includes(saved as AppLocale)) {
            return saved as AppLocale;
        }
        return LocaleHelper.getSystemLocale();
    }

    static setUserLocale(locale: AppLocale): void {
        cc.sys.localStorage.setItem('user_locale', locale);
    }

    static isRTL(locale: AppLocale): boolean {
        return false; // Add Arabic/Hebrew if supported
    }
}

// Usage:
const locale: AppLocale = LocaleHelper.getUserLocale();
cc.log('Current locale:', locale); // e.g., 'en'
```

This provides compile-time type safety and maps Cocos2d-x language constants to application-specific values.
